'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { ChatList } from '@/components/chat/ChatList';
import { ChatWindow } from '@/components/chat/ChatWindow';
import { collection, query, where, onSnapshot } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Chat, User } from '@/types';
import { Loader2 } from 'lucide-react';
import { useSearchParams, useRouter } from 'next/navigation';

export default function MessagesPage() {
    const { userData, loading: authLoading } = useAuth();
    const router = useRouter();
    const searchParams = useSearchParams();

    const [chats, setChats] = useState<Chat[]>([]);
    const [loadingChats, setLoadingChats] = useState(true);

    // State for the currently active chat
    const [selectedChatId, setSelectedChatId] = useState<string | null>(null);
    const [selectedUser, setSelectedUser] = useState<{ name: string; profilePic: string; uid: string } | null>(null);

    // 1. Fetch user's chats
    useEffect(() => {
        if (!userData?.uid) {
            setLoadingChats(false);
            return;
        }

        const chatsRef = collection(db, 'chats');
        const q = query(
            chatsRef,
            where('participants', 'array-contains', userData.uid),
        );

        const unsubscribe = onSnapshot(q, (snapshot) => {
            const fetchedChats = snapshot.docs.map(doc => ({
                id: doc.id,
                ...doc.data()
            })) as Chat[];

            // Sort client-side
            fetchedChats.sort((a, b) => {
                const timeA = typeof a.lastMessageAt?.toMillis === 'function' ? a.lastMessageAt.toMillis() : Date.now();
                const timeB = typeof b.lastMessageAt?.toMillis === 'function' ? b.lastMessageAt.toMillis() : Date.now();
                return timeB - timeA;
            });

            setChats(fetchedChats);
            setLoadingChats(false);
        }, (error) => {
            console.error('Error fetching chats:', error);
            setLoadingChats(false);
        });

        return () => unsubscribe();
    }, [userData?.uid]);

    // 2. Handle 'new' chat from URL query parameters (e.g. clicking "Message" on someone's profile)
    useEffect(() => {
        const userId = searchParams.get('userId');
        const userName = searchParams.get('name');
        const userPic = searchParams.get('pic');

        if (userId && userName && userData?.uid) {
            const tempUser = {
                uid: userId,
                name: userName,
                profilePic: userPic || '',
            } as User;
            handleStartChat(tempUser);

            // Clean up URL so refresh doesn't trigger it again
            router.replace('/messages');
        }
    }, [searchParams, userData?.uid, router]);

    // Helper to generate a consistent chat ID between two users
    const getChatId = (uid1: string, uid2: string) => {
        return uid1 < uid2 ? `${uid1}_${uid2}` : `${uid2}_${uid1}`;
    };

    const handleStartChat = (otherUser: User) => {
        if (!userData?.uid) return;

        const chatId = getChatId(userData.uid, otherUser.uid);
        setSelectedChatId(chatId);
        setSelectedUser({
            uid: otherUser.uid,
            name: otherUser.name,
            profilePic: otherUser.profilePic || '',
        });
    };

    const handleSelectChat = (chatId: string) => {
        setSelectedChatId(chatId);

        // Find the other user's info from the chat document
        const chat = chats.find(c => c.id === chatId);
        if (chat && userData?.uid) {
            const otherUid = chat.participants.find(id => id !== userData.uid);
            if (otherUid && chat.participantDetails?.[otherUid]) {
                setSelectedUser({
                    uid: otherUid,
                    name: chat.participantDetails[otherUid].name,
                    profilePic: chat.participantDetails[otherUid].profilePic,
                });
            }
        }
    };

    if (authLoading) {
        return (
            <div className="flex h-[calc(100vh-4rem)] items-center justify-center">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
            </div>
        );
    }

    if (!userData) {
        return (
            <div className="flex h-[calc(100vh-4rem)] items-center justify-center">
                <p className="text-gray-500">Please log in to view messages.</p>
            </div>
        );
    }

    return (
        <div className="h-[calc(100vh-4rem)] bg-white max-w-6xl mx-auto md:p-4 p-0">
            <div className="flex bg-white md:rounded-xl shadow-sm border overflow-hidden h-full">

                {/* Left Pane: Chat List */}
                <div className={`md:w-1/3 w-full border-r ${selectedChatId ? 'hidden md:block' : 'block'}`}>
                    {loadingChats ? (
                        <div className="flex h-full items-center justify-center">
                            <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
                        </div>
                    ) : (
                        <ChatList
                            currentUser={userData}
                            chats={chats}
                            onSelectChat={handleSelectChat}
                            onStartChat={handleStartChat}
                            selectedChatId={selectedChatId}
                        />
                    )}
                </div>

                {/* Right Pane: Active Chat Window */}
                <div className={`flex-1 overflow-hidden ${!selectedChatId ? 'hidden md:flex' : 'flex'}`}>
                    <ChatWindow
                        chatId={selectedChatId || ''}
                        currentUser={userData}
                        otherUser={selectedUser}
                        onBack={() => {
                            setSelectedChatId(null);
                            setSelectedUser(null);
                        }}
                    />
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState, useEffect } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { collection, query, orderBy, onSnapshot, addDoc, updateDoc, deleteDoc, doc, serverTimestamp } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Post } from '@/types';
import { PostCard } from '@/components/feed/PostCard';
import { CreatePostModal } from '@/components/modals/CreatePostModal';
import { EditPostModal } from '@/components/modals/EditPostModal';
import { CommentModal } from '@/components/modals/CommentModal';
import { ConfirmDialog } from '@/components/modals/ConfirmDialog';
import { PenSquare, Camera, Image as ImageIcon, Paperclip } from 'lucide-react';
import Link from 'next/link';

export default function HomePage() {
  const { user, userData, signOut, loading: authLoading } = useAuth();
  const [posts, setPosts] = useState<Post[]>([]);
  const [loading, setLoading] = useState(true);
  const [showCreatePost, setShowCreatePost] = useState(false);
  const [editingPost, setEditingPost] = useState<Post | null>(null);
  const [commentingPost, setCommentingPost] = useState<Post | null>(null);
  const [deletingPostId, setDeletingPostId] = useState<string | null>(null);

  // Fetch posts from Firebase
  useEffect(() => {
    if (!userData) {
      setTimeout(() => setLoading(false), 0);
      return;
    }

    const postsQuery = query(
      collection(db, 'posts'),
      orderBy('createdAt', 'desc')
    );

    const unsubscribe = onSnapshot(postsQuery, (snapshot) => {
      const fetchedPosts = snapshot.docs.map(doc => ({
        id: doc.id,
        ...doc.data()
      })) as Post[];
      setPosts(fetchedPosts);
      setLoading(false);
    });

    return () => unsubscribe();
  }, [userData]);

  const handleCreatePost = async (content: string, imageUrl?: string) => {
    if (!userData) return;

    await addDoc(collection(db, 'posts'), {
      authorUid: userData.uid,
      authorName: userData.name,
      authorBatch: userData.batch,
      authorProfilePic: userData.profilePic,
      content,
      imageUrl: imageUrl || '',
      likes: [],
      comments: [],
      createdAt: serverTimestamp()
    });
  };

  const handleUpdatePost = async (postId: string, newContent: string) => {
    const postRef = doc(db, 'posts', postId);
    await updateDoc(postRef, { content: newContent });
  };

  const handleLikePost = async (postId: string, isLiked: boolean) => {
    if (!userData) return;

    const postRef = doc(db, 'posts', postId);
    const post = posts.find(p => p.id === postId);
    if (!post) return;

    const likes = post.likes || [];
    const updatedLikes = isLiked
      ? likes.filter(uid => uid !== userData.uid)
      : [...likes, userData.uid];

    await updateDoc(postRef, { likes: updatedLikes });
  };

  const handleAddComment = async (text: string) => {
    if (!userData || !commentingPost) return;

    const postRef = doc(db, 'posts', commentingPost.id);
    const post = posts.find(p => p.id === commentingPost.id);
    if (!post) return;

    const newComment = {
      authorUid: userData.uid,
      authorName: userData.name,
      text,
      createdAt: new Date()
    };

    const updatedComments = [...(post.comments || []), newComment];
    await updateDoc(postRef, { comments: updatedComments });
  };

  const handleDeletePost = async () => {
    if (!deletingPostId) return;
    await deleteDoc(doc(db, 'posts', deletingPostId));
    setDeletingPostId(null);
  };

  if (authLoading || loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-brand-burgundy mx-auto mb-4"></div>
          <p className="text-brand-ebony font-serif italic">Gathering the tribe...</p>
        </div>
      </div>
    );
  }

  if (!userData) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center p-8 bg-brand-parchment/80 rounded-2xl shadow-xl max-w-sm w-full mx-4 border border-brand-ebony/10">
          <div className="w-16 h-16 bg-brand-burgundy/10 rounded-full flex items-center justify-center mx-auto mb-6">
            <span className="text-2xl">🤝</span>
          </div>
          <h2 className="text-2xl font-serif font-bold mb-4 text-brand-ebony">Welcome back!</h2>

          {user ? (
            <>
              <p className="text-brand-ebony/70 mb-6">
                We found your account, but your profile details are missing.
                This usually happens if the final step of registration was interrupted.
              </p>
              <div className="flex flex-col gap-3">
                <Link href="/signup" className="w-full px-6 py-3 bg-brand-burgundy text-white rounded-lg font-semibold hover:bg-[#5a2427] transition text-center">
                  Create Profile
                </Link>
                <button
                  onClick={() => signOut()}
                  className="w-full px-6 py-3 border border-brand-ebony/20 text-brand-ebony/80 rounded-lg hover:bg-brand-ebony/5 transition"
                >
                  Log Out & Try Again
                </button>
              </div>
            </>
          ) : (
            <>
              <p className="text-brand-ebony/70 mb-6">Connect with fellow alumni from Loyola School Jamshedpur.</p>
              <div className="space-y-3">
                <Link href="/login" className="block w-full px-6 py-3 bg-brand-burgundy text-white rounded-lg font-semibold hover:bg-[#5a2427] transition text-center">
                  Log In
                </Link>
                <Link href="/signup" className="block w-full px-6 py-3 border border-brand-burgundy/30 text-brand-burgundy rounded-lg font-semibold hover:bg-brand-burgundy/5 transition text-center">
                  Sign Up
                </Link>
              </div>
            </>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto p-4 pt-8">
      {/* Feed Header */}
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-3">
          <div className="h-10 w-1 bg-brand-burgundy rounded-full" />
          <h1 className="text-3xl font-serif font-bold text-brand-ebony tracking-tight">The Feed</h1>
        </div>
        <div className="text-[10px] font-bold text-brand-gold uppercase tracking-[0.3em] bg-brand-gold/5 px-4 py-1.5 rounded-full border border-brand-gold/20 shadow-inner">
          Premium Alumni Network
        </div>
      </div>

      {/* Create Post Button Area */}
      <div className="bg-brand-parchment/40 rounded-2xl border border-brand-ebony/10 p-5 mb-8 shadow-sm backdrop-blur-sm group hover:border-brand-burgundy/20 transition-all duration-300">
        <div className="flex items-start gap-4 mb-4">
          <img
            src={userData.profilePic || `https://placehold.co/100x100/EFEFEFF/3D2B27?text=${userData.name.substring(0, 1)}`}
            alt={userData.name}
            className="w-12 h-12 rounded-full border-2 border-white shadow-sm"
          />
          <button
            onClick={() => setShowCreatePost(true)}
            className="flex-1 text-left px-5 py-3 bg-white/60 hover:bg-white border border-brand-ebony/10 rounded-xl text-brand-ebony/40 transition-all font-medium group-hover:shadow-inner"
          >
            Share something with your fellow alumni...
          </button>
        </div>
        <div className="flex items-center justify-between pt-4 border-t border-brand-ebony/5">
          <div className="flex gap-2">
            <button onClick={() => setShowCreatePost(true)} className="p-2.5 text-brand-ebony/30 hover:text-brand-burgundy hover:bg-brand-burgundy/5 rounded-xl transition-all">
              <Camera className="w-5 h-5" />
            </button>
            <button onClick={() => setShowCreatePost(true)} className="p-2.5 text-brand-ebony/30 hover:text-brand-burgundy hover:bg-brand-burgundy/5 rounded-xl transition-all">
              <ImageIcon className="w-5 h-5" />
            </button>
            <button onClick={() => setShowCreatePost(true)} className="p-2.5 text-brand-ebony/30 hover:text-brand-burgundy hover:bg-brand-burgundy/5 rounded-xl transition-all">
              <Paperclip className="w-5 h-5" />
            </button>
          </div>
          <button
            onClick={() => setShowCreatePost(true)}
            className="px-8 py-2 bg-brand-burgundy text-white rounded-xl font-bold hover:bg-[#5a2427] transition-all shadow-md shadow-brand-burgundy/20 hover:shadow-lg active:scale-95"
          >
            Post
          </button>
        </div>
      </div>

      {/* Posts Feed */}
      <div className="space-y-4">
        {posts.length > 0 ? (
          posts.map(post => (
            <PostCard
              key={post.id}
              post={post}
              currentUser={userData}
              onLike={(isLiked) => handleLikePost(post.id, isLiked)}
              onComment={() => setCommentingPost(post)}
              onEdit={() => setEditingPost(post)}
              onDelete={() => setDeletingPostId(post.id)}
            />
          ))
        ) : (
          <div className="bg-white rounded-xl shadow-sm p-8 text-center">
            <p className="text-gray-500">No posts yet. Be the first to share something!</p>
          </div>
        )}
      </div>

      {/* Modals */}
      <CreatePostModal
        isOpen={showCreatePost}
        onClose={() => setShowCreatePost(false)}
        onSubmit={handleCreatePost}
        currentUser={userData}
      />

      {editingPost && (
        <EditPostModal
          isOpen={true}
          onClose={() => setEditingPost(null)}
          onSubmit={handleUpdatePost}
          post={editingPost}
        />
      )}

      {commentingPost && (
        <CommentModal
          isOpen={true}
          onClose={() => setCommentingPost(null)}
          onSubmit={handleAddComment}
          comments={commentingPost.comments || []}
          postAuthor={commentingPost.authorName}
        />
      )}

      <ConfirmDialog
        isOpen={!!deletingPostId}
        onClose={() => setDeletingPostId(null)}
        onConfirm={handleDeletePost}
        title="Delete Post"
        message="Are you sure you want to delete this post? This action cannot be undone."
        confirmText="Delete"
        variant="danger"
      />
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useAuth } from '@/contexts/AuthContext';
import { useRouter } from 'next/navigation';
import { uploadMedia } from '@/lib/media';
import { Eye, EyeOff, Loader2, Camera, ArrowLeft } from 'lucide-react';
import Link from 'next/link';
import { LocationAutocomplete } from '@/components/ui/LocationAutocomplete';

export default function SignUpPage() {
    const { signUp, error, clearError } = useAuth();
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [showPassword, setShowPassword] = useState(false);
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        batch: new Date().getFullYear(),
        profession: '',
        location: '',
    });
    const [profilePicFile, setProfilePicFile] = useState<File | null>(null);
    const [previewUrl, setPreviewUrl] = useState<string>('');

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            // Validate file size (max 5MB)
            if (file.size > 5 * 1024 * 1024) {
                alert('Image size should be less than 5MB');
                return;
            }

            // Validate file type
            if (!file.type.startsWith('image/')) {
                alert('Please select an image file');
                return;
            }

            setProfilePicFile(file);
            setPreviewUrl(URL.createObjectURL(file));
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        clearError();

        try {
            let profilePicUrl = '';
            if (profilePicFile) {
                profilePicUrl = await uploadMedia(profilePicFile, 'profiles') || '';
            }

            await signUp(formData.email, formData.password, {
                name: formData.name,
                batch: formData.batch,
                profession: formData.profession,
                location: formData.location,
                profilePic: profilePicUrl || `https://placehold.co/100x100/EFEFEFF/003366?text=${formData.name.substring(0, 2).toUpperCase()}`,
            });

            router.push('/');
        } catch (err) {
            console.error('Sign up failed:', err);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-brand-cream border-brand-ebony/5 flex items-center justify-center p-4 relative overflow-hidden">
            {/* Decorative Background Leaves */}
            <div className="absolute top-0 left-0 w-64 h-64 opacity-5 pointer-events-none -translate-x-1/4 -translate-y-1/4 rotate-45">
                <svg viewBox="0 0 200 200" className="w-full h-full fill-brand-ebony">
                    <path d="M40,100 C40,100 80,40 160,40 C160,40 100,100 40,100 Z" />
                </svg>
            </div>
            <div className="absolute bottom-0 right-0 w-64 h-64 opacity-5 pointer-events-none translate-x-1/4 translate-y-1/4 -rotate-12">
                <svg viewBox="0 0 200 200" className="w-full h-full fill-brand-ebony">
                    <path d="M40,100 C40,100 80,40 160,40 C160,40 100,100 40,100 Z" />
                </svg>
            </div>

            <div className="max-w-md w-full relative z-10">
                {/* Back Button */}
                <Link href="/login" className="inline-flex items-center gap-2 text-brand-ebony/60 hover:text-brand-burgundy mb-6 font-medium transition-colors">
                    <ArrowLeft className="w-4 h-4" />
                    Back to Login
                </Link>

                {/* Card */}
                <div className="bg-brand-parchment/80 rounded-2xl shadow-xl p-8 border border-brand-ebony/10 backdrop-blur-sm">
                    {/* Header */}
                    <div className="text-center mb-8">
                        <div className="w-16 h-16 bg-brand-burgundy rounded-full flex items-center justify-center mx-auto mb-4 overflow-hidden border-2 border-white shadow-lg">
                            <div className="w-full h-full flex items-center justify-center bg-brand-burgundy">
                                <span className="text-2xl font-bold text-white font-serif">A</span>
                            </div>
                        </div>
                        <h1 className="text-3xl font-serif font-bold text-brand-ebony mb-2">Join Alumni Network</h1>
                        <p className="text-brand-ebony/60">Create your account to connect with fellow alumni</p>
                    </div>

                    {/* Error Message */}
                    {error && (
                        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg">
                            <p className="text-sm text-red-600">{error}</p>
                        </div>
                    )}

                    {/* Form */}
                    <form onSubmit={handleSubmit} className="space-y-4">
                        {/* Profile Picture */}
                        <div className="flex flex-col items-center mb-6">
                            <div className="relative group">
                                <div className="w-24 h-24 rounded-full overflow-hidden bg-gray-200 border-4 border-gray-100 shadow-md">
                                    {previewUrl ? (
                                        <img src={previewUrl} alt="Preview" className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center text-gray-400">
                                            <svg className="w-12 h-12" fill="currentColor" viewBox="0 0 20 20">
                                                <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                                            </svg>
                                        </div>
                                    )}
                                </div>
                                {/* Camera overlay */}
                                <label className="absolute inset-0 flex items-center justify-center bg-black bg-opacity-40 rounded-full opacity-0 group-hover:opacity-100 transition cursor-pointer">
                                    <Camera className="w-8 h-8 text-white" />
                                    <input type="file" accept="image/*" onChange={handleFileChange} className="hidden" />
                                </label>
                            </div>
                            <label className="mt-3 cursor-pointer text-brand-burgundy hover:text-[#5a2427] text-sm font-bold uppercase tracking-widest">
                                Upload Photo (Optional)
                                <input type="file" accept="image/*" onChange={handleFileChange} className="hidden" />
                            </label>
                            <p className="text-[10px] text-brand-ebony/40 mt-1 uppercase tracking-widest font-bold">Max size: 5MB</p>
                        </div>

                        {/* Name */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Full Name <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="text"
                                placeholder="John Doe"
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                className="w-full px-4 py-3 bg-white/50 border border-brand-ebony/10 rounded-xl focus:ring-2 focus:ring-brand-burgundy/20 focus:border-brand-burgundy transition outline-none text-brand-ebony"
                                required
                            />
                        </div>

                        {/* Email */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Email Address <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="email"
                                placeholder="your.email@example.com"
                                value={formData.email}
                                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                                className="w-full px-4 py-3 bg-white/50 border border-brand-ebony/10 rounded-xl focus:ring-2 focus:ring-brand-burgundy/20 focus:border-brand-burgundy transition outline-none text-brand-ebony"
                                required
                            />
                        </div>

                        {/* Password */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Password <span className="text-red-500">*</span>
                            </label>
                            <div className="relative">
                                <input
                                    type={showPassword ? 'text' : 'password'}
                                    placeholder="Minimum 6 characters"
                                    value={formData.password}
                                    onChange={(e) => setFormData({ ...formData, password: e.target.value })}
                                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition pr-12"
                                    required
                                    minLength={6}
                                />
                                <button
                                    type="button"
                                    onClick={() => setShowPassword(!showPassword)}
                                    className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700"
                                >
                                    {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                                </button>
                            </div>
                        </div>

                        {/* Batch Year */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Batch Year <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="number"
                                placeholder="e.g., 2020"
                                value={formData.batch}
                                onChange={(e) => setFormData({ ...formData, batch: parseInt(e.target.value) })}
                                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition"
                                required
                                min={1950}
                                max={new Date().getFullYear()}
                            />
                        </div>

                        {/* Profession */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Profession <span className="text-red-500">*</span>
                            </label>
                            <input
                                type="text"
                                placeholder="e.g., Software Engineer"
                                value={formData.profession}
                                onChange={(e) => setFormData({ ...formData, profession: e.target.value })}
                                className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition"
                                required
                            />
                        </div>

                        {/* Location */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">
                                Location <span className="text-red-500">*</span>
                            </label>
                            <LocationAutocomplete
                                value={formData.location}
                                onChange={(location) => setFormData({ ...formData, location })}
                            />
                        </div>

                        {/* Submit Button */}
                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full py-3 bg-brand-burgundy text-white rounded-xl font-bold hover:bg-[#5a2427] transition-all shadow-md shadow-brand-burgundy/20 hover:shadow-lg disabled:opacity-50 disabled:cursor-not-allowed mt-6 uppercase tracking-widest text-sm"
                        >
                            {loading ? (
                                <span className="flex items-center justify-center gap-2">
                                    <Loader2 className="w-5 h-5 animate-spin" />
                                    Creating...
                                </span>
                            ) : (
                                'Create Account'
                            )}
                        </button>
                    </form>

                    {/* Login Link */}
                    <div className="text-center mt-6">
                        <p className="text-brand-ebony/60">
                            Already have an account?{' '}
                            <Link href="/login" className="text-brand-burgundy hover:underline font-bold">
                                Log In
                            </Link>
                        </p>
                    </div>
                </div>

                {/* Footer */}
                <p className="text-center text-xs font-bold text-brand-ebony/40 mt-6 uppercase tracking-[0.2em]">
                    © 2024 Loyola Alumni Association • For the Tribe.
                </p>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { Chat, User } from '@/types';
import { collection, query, getDocs, where } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Search, Loader2 } from 'lucide-react';
import { formatDistanceToNow } from 'date-fns';

interface ChatListProps {
    currentUser: User;
    chats: Chat[];
    onSelectChat: (chatId: string) => void;
    onStartChat: (otherUser: User) => void;
    selectedChatId: string | null;
}

export function ChatList({ currentUser, chats, onSelectChat, onStartChat, selectedChatId }: ChatListProps) {
    const [searchQuery, setSearchQuery] = useState('');
    const [searchResults, setSearchResults] = useState<User[]>([]);
    const [isSearching, setIsSearching] = useState(false);

    useEffect(() => {
        const searchUsers = async () => {
            if (!searchQuery.trim()) {
                setSearchResults([]);
                return;
            }

            setIsSearching(true);
            try {
                // Perform a simple search for users.
                // In a production app, Algolia or a similar service is recommended for full-text search.
                const usersRef = collection(db, 'users');
                const q = query(usersRef, where('name', '>=', searchQuery), where('name', '<=', searchQuery + '\uf8ff'));
                const querySnapshot = await getDocs(q);

                const results: User[] = [];
                querySnapshot.forEach((doc) => {
                    const user = doc.data() as User;
                    if (user.uid !== currentUser.uid) {
                        results.push(user);
                    }
                });
                setSearchResults(results);
            } catch (error) {
                console.error('Error searching users:', error);
            } finally {
                setIsSearching(false);
            }
        };

        const timeoutId = setTimeout(searchUsers, 500); // Debounce
        return () => clearTimeout(timeoutId);
    }, [searchQuery, currentUser.uid]);

    return (
        <div className="w-full h-full flex flex-col bg-white border-r">
            {/* Header & Search */}
            <div className="p-4 border-b">
                <h2 className="text-xl font-bold text-gray-900 mb-4">Messages</h2>
                <div className="relative">
                    <input
                        type="text"
                        placeholder="Search alumni to chat..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                    />
                    <Search className="w-5 h-5 text-gray-400 absolute left-3 top-1/2 -translate-y-1/2" />
                </div>
            </div>

            {/* List Content */}
            <div className="flex-1 overflow-y-auto">
                {searchQuery ? (
                    // Search Results
                    <div className="p-2">
                        {isSearching ? (
                            <div className="flex justify-center py-4">
                                <Loader2 className="w-6 h-6 animate-spin text-blue-600" />
                            </div>
                        ) : searchResults.length > 0 ? (
                            searchResults.map((user) => (
                                <button
                                    key={user.uid}
                                    onClick={() => {
                                        onStartChat(user);
                                        setSearchQuery('');
                                    }}
                                    className="w-full flex items-center p-3 hover:bg-gray-50 rounded-lg transition-colors"
                                >
                                    <img
                                        src={user.profilePic || `https://placehold.co/100x100/EFEFEFF/003366?text=${user.name.substring(0, 1)}`}
                                        alt={user.name}
                                        className="w-12 h-12 rounded-full object-cover mr-3"
                                    />
                                    <div className="text-left flex-1">
                                        <p className="font-semibold text-gray-900">{user.name}</p>
                                        <p className="text-sm text-gray-500 line-clamp-1">{user.profession || `Batch of ${user.batch}`}</p>
                                    </div>
                                </button>
                            ))
                        ) : (
                            <p className="text-center py-4 text-gray-500 text-sm">No alumni found matching "{searchQuery}"</p>
                        )}
                    </div>
                ) : (
                    // Active Chats
                    <div className="p-2">
                        {chats.length === 0 ? (
                            <div className="text-center py-8 text-gray-500">
                                <MessageSquare className="w-12 h-12 mx-auto text-gray-300 mb-3" />
                                <p>No active conversations.</p>
                                <p className="text-sm">Search above to start chatting!</p>
                            </div>
                        ) : (
                            chats.map((chat) => {
                                const otherUserId = chat.participants.find(id => id !== currentUser.uid);
                                const otherUserDetails = otherUserId ? chat.participantDetails?.[otherUserId] : null;

                                const name = otherUserDetails?.name || 'Unknown User';
                                const profilePic = otherUserDetails?.profilePic || `https://placehold.co/100x100/EFEFEFF/003366?text=${name.substring(0, 1)}`;
                                const unreadCount = chat.unreadCount?.[currentUser.uid] || 0;

                                return (
                                    <button
                                        key={chat.id}
                                        onClick={() => onSelectChat(chat.id)}
                                        className={`w-full flex items-center p-3 rounded-lg transition-colors mb-1 ${selectedChatId === chat.id ? 'bg-blue-50' : 'hover:bg-gray-50'
                                            }`}
                                    >
                                        <div className="relative">
                                            <img
                                                src={profilePic}
                                                alt={name}
                                                className="w-12 h-12 rounded-full object-cover mr-3"
                                            />
                                        </div>
                                        <div className="text-left flex-1 min-w-0">
                                            <div className="flex justify-between items-baseline mb-1">
                                                <p className={`font-semibold truncate pr-2 ${unreadCount > 0 ? 'text-gray-900' : 'text-gray-700'}`}>
                                                    {name}
                                                </p>
                                                {chat.lastMessageAt && (
                                                    <span className="text-xs text-gray-400 whitespace-nowrap">
                                                        {formatDistanceToNow(chat.lastMessageAt.toDate(), { addSuffix: true })}
                                                    </span>
                                                )}
                                            </div>
                                            <p className={`text-sm truncate ${unreadCount > 0 ? 'font-medium text-gray-900' : 'text-gray-500'}`}>
                                                {chat.lastMessage || 'Start a conversation'}
                                            </p>
                                        </div>
                                        {unreadCount > 0 && (
                                            <div className="ml-3 bg-blue-600 text-white text-xs font-bold rounded-full w-5 h-5 flex items-center justify-center">
                                                {unreadCount > 99 ? '99+' : unreadCount}
                                            </div>
                                        )}
                                    </button>
                                );
                            })
                        )}
                    </div>
                )}
            </div>
        </div>
    );
}

// Need to import MessageSquare here
import { MessageSquare } from 'lucide-react';

import React, { useState, useEffect, useRef } from 'react';
import { User, Message } from '@/types';
import { collection, query, orderBy, onSnapshot, addDoc, serverTimestamp, setDoc, doc, updateDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { MessageBubble } from './MessageBubble';
import { Send, Loader2, ArrowLeft } from 'lucide-react';

interface ChatWindowProps {
    chatId: string;
    currentUser: User;
    otherUser: { name: string; profilePic: string; uid: string } | null;
    onBack?: () => void; // For mobile view
}

export function ChatWindow({ chatId, currentUser, otherUser, onBack }: ChatWindowProps) {
    const [messages, setMessages] = useState<Message[]>([]);
    const [newMessage, setNewMessage] = useState('');
    const [loading, setLoading] = useState(true);
    const [sending, setSending] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    // Scroll to bottom when messages change
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    // Fetch messages
    useEffect(() => {
        if (!chatId) return;

        setLoading(true);
        const messagesRef = collection(db, 'chats', chatId, 'messages');
        const q = query(messagesRef, orderBy('createdAt', 'asc'));

        const unsubscribe = onSnapshot(q, (snapshot) => {
            const fetchedMessages = snapshot.docs.map(doc => ({
                id: doc.id,
                ...doc.data()
            })) as Message[];

            setMessages(fetchedMessages);
            setLoading(false);

            // Mark messages as read (optional enhancement: only update if there are unread messages)
            if (fetchedMessages.length > 0 && currentUser.uid) {
                // In a production app, we would update the chat document's unreadCount for the currentUser to 0 here.
            }

        }, (error) => {
            console.error('Error fetching messages:', error);
            setLoading(false);
        });

        return () => unsubscribe();
    }, [chatId, currentUser.uid]);

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newMessage.trim() || !otherUser || !chatId) return;

        const messageText = newMessage.trim();
        setNewMessage(''); // optimistic UI clear
        setSending(true);

        try {
            // 1. Add the message to the subcollection
            const messageData = {
                text: messageText,
                senderId: currentUser.uid,
                senderName: currentUser.name,
                senderProfilePic: currentUser.profilePic || null,
                createdAt: serverTimestamp(),
                isRead: false
            };

            await addDoc(collection(db, 'chats', chatId, 'messages'), messageData);

            // 2. Update (or create) the parent chat document
            const chatRef = doc(db, 'chats', chatId);

            await setDoc(chatRef, {
                participants: [currentUser.uid, otherUser.uid],
                lastMessage: messageText,
                lastMessageAt: serverTimestamp(),
                // Simplistic unread count logic (just tracking the fact there is a message)
                participantDetails: {
                    [currentUser.uid]: {
                        name: currentUser.name,
                        profilePic: currentUser.profilePic || null
                    },
                    [otherUser.uid]: {
                        name: otherUser.name,
                        profilePic: otherUser.profilePic || null
                    }
                }
            }, { merge: true });

        } catch (error) {
            console.error('Error sending message:', error);
            // Re-set message if failed
            setNewMessage(messageText);
        } finally {
            setSending(false);
        }
    };

    if (!otherUser) {
        return (
            <div className="flex-1 flex flex-col items-center justify-center bg-gray-50 text-gray-500">
                <div className="w-24 h-24 bg-gray-200 rounded-full flex items-center justify-center mb-4">
                    <Send className="w-10 h-10 text-gray-400 ml-1" />
                </div>
                <h3 className="text-xl font-semibold text-gray-700">Your Messages</h3>
                <p>Select a chat or search for an alumni to start talking.</p>
            </div>
        );
    }

    return (
        <div className="flex-1 flex flex-col h-full bg-gray-50">
            {/* Chat Header */}
            <div className="flex items-center p-4 bg-white border-b shadow-sm z-10">
                {onBack && (
                    <button onClick={onBack} className="md:hidden mr-3 text-gray-600 hover:text-gray-900">
                        <ArrowLeft className="w-6 h-6" />
                    </button>
                )}
                <img
                    src={otherUser.profilePic || `https://placehold.co/100x100/EFEFEFF/003366?text=${otherUser.name.substring(0, 1)}`}
                    alt={otherUser.name}
                    className="w-10 h-10 rounded-full mr-3 object-cover shadow-sm"
                />
                <div>
                    <h3 className="font-semibold text-gray-900">{otherUser.name}</h3>
                </div>
            </div>

            {/* Messages Area */}
            <div className="flex-1 overflow-y-auto p-4 space-y-2">
                {loading ? (
                    <div className="flex justify-center items-center h-full">
                        <Loader2 className="w-8 h-8 animate-spin text-blue-600" />
                    </div>
                ) : messages.length === 0 ? (
                    <div className="flex flex-col items-center justify-center h-full text-gray-500 space-y-3">
                        <img
                            src={otherUser.profilePic || `https://placehold.co/100x100/EFEFEFF/003366?text=${otherUser.name.substring(0, 1)}`}
                            alt={otherUser.name}
                            className="w-20 h-20 rounded-full object-cover shadow-sm opacity-50"
                        />
                        <p>This is the beginning of your conversation with <strong>{otherUser.name}</strong>.</p>
                    </div>
                ) : (
                    messages.map((message) => (
                        <MessageBubble
                            key={message.id}
                            message={message}
                            isOwnMessage={message.senderId === currentUser.uid}
                        />
                    ))
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-white border-t">
                <form onSubmit={handleSendMessage} className="flex items-center gap-2">
                    <input
                        type="text"
                        value={newMessage}
                        onChange={(e) => setNewMessage(e.target.value)}
                        placeholder="Type a message..."
                        className="flex-1 px-4 py-3 border border-gray-300 rounded-full focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none bg-gray-50"
                        disabled={sending}
                    />
                    <button
                        type="submit"
                        disabled={!newMessage.trim() || sending}
                        className="p-3 bg-blue-600 text-white rounded-full hover:bg-blue-700 transition disabled:opacity-50 disabled:cursor-not-allowed shadow-sm flex items-center justify-center"
                    >
                        {sending ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5 ml-1" />}
                    </button>
                </form>
            </div>
        </div>
    );
}

import React from 'react';
import { Message } from '@/types';
import { format } from 'date-fns';

interface MessageBubbleProps {
    message: Message;
    isOwnMessage: boolean;
}

export function MessageBubble({ message, isOwnMessage }: MessageBubbleProps) {
    const timeString = message.createdAt
        ? format(message.createdAt.toDate(), 'h:mm a')
        : '';

    return (
        <div className={`flex w-full mb-4 ${isOwnMessage ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex max-w-[70%] ${isOwnMessage ? 'flex-row-reverse' : 'flex-row'} items-end gap-2`}>
                {!isOwnMessage && message.senderProfilePic && (
                    <img
                        src={message.senderProfilePic}
                        alt={message.senderName || 'Sender'}
                        className="w-8 h-8 rounded-full flex-shrink-0"
                    />
                )}
                <div
                    className={`px-4 py-2 rounded-2xl relative ${isOwnMessage
                            ? 'bg-blue-600 text-white rounded-br-none'
                            : 'bg-white border border-gray-200 text-gray-800 rounded-bl-none'
                        }`}
                >
                    <p className="text-sm whitespace-pre-wrap word-break break-words">
                        {message.text}
                    </p>
                    <span className={`text-[10px] block mt-1 ${isOwnMessage ? 'text-blue-100 text-right' : 'text-gray-400 text-left'}`}>
                        {timeString}
                    </span>
                </div>
            </div>
        </div>
    );
}

'use client';

import { Post, User } from '@/types';
import { Heart, MessageCircle, Share2, MoreHorizontal, Pencil, Trash2 } from 'lucide-react';
import { useState } from 'react';

interface PostCardProps {
    post: Post;
    currentUser: User;
    onLike: (isLiked: boolean) => void;
    onComment: () => void;
    onEdit?: () => void;
    onDelete?: () => void;
}

export const PostCard: React.FC<PostCardProps> = ({
    post,
    currentUser,
    onLike,
    onComment,
    onEdit,
    onDelete,
}) => {
    const [showMenu, setShowMenu] = useState(false);
    const isLiked = post.likes?.includes(currentUser.uid) || false;
    const isOwnPost = post.authorUid === currentUser.uid;

    const formatTimestamp = (timestamp: unknown) => {
        if (!timestamp) return 'Just now';
        const date = (timestamp as { toDate?: () => Date }).toDate ? (timestamp as { toDate: () => Date }).toDate() : new Date(timestamp as string | number | Date);
        const now = new Date();
        const diffInMs = now.getTime() - date.getTime();
        const diffInMins = Math.floor(diffInMs / 60000);
        const diffInHours = Math.floor(diffInMs / 3600000);
        const diffInDays = Math.floor(diffInMs / 86400000);

        if (diffInMins < 1) return 'Just now';
        if (diffInMins < 60) return `${diffInMins}m ago`;
        if (diffInHours < 24) return `${diffInHours}h ago`;
        if (diffInDays < 7) return `${diffInDays}d ago`;
        return date.toLocaleDateString();
    };

    return (
        <div className="bg-brand-parchment/60 rounded-2xl shadow-sm border border-brand-ebony/10 p-5 transition-all hover:shadow-md backdrop-blur-sm">
            {/* Header */}
            <div className="flex items-start justify-between mb-3">
                <div className="flex items-center gap-3">
                    <img
                        src={post.authorProfilePic || `https://placehold.co/40x40/EFEFEFF/003366?text=${post.authorName.substring(0, 1)}`}
                        alt={post.authorName}
                        className="w-10 h-10 rounded-full"
                    />
                    <div className="flex flex-col">
                        <h3 className="font-serif font-bold text-lg text-brand-ebony leading-none mb-1">{post.authorName}</h3>
                        <p className="text-xs font-medium text-brand-ebony/50 uppercase tracking-widest">
                            Class of {post.authorBatch} • {formatTimestamp(post.createdAt)}
                        </p>
                    </div>
                </div>

                {isOwnPost && (
                    <div className="relative">
                        <button
                            onClick={() => setShowMenu(!showMenu)}
                            className="p-2 hover:bg-brand-ebony/5 rounded-full transition"
                        >
                            <MoreHorizontal className="w-5 h-5 text-brand-ebony/60" />
                        </button>

                        {showMenu && (
                            <div className="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-lg border border-gray-200 py-1 z-10">
                                {onEdit && (
                                    <button
                                        onClick={() => {
                                            onEdit();
                                            setShowMenu(false);
                                        }}
                                        className="w-full px-4 py-2 text-left hover:bg-gray-100 flex items-center gap-2"
                                    >
                                        <Pencil className="w-4 h-4" />
                                        Edit Post
                                    </button>
                                )}
                                {onDelete && (
                                    <button
                                        onClick={() => {
                                            onDelete();
                                            setShowMenu(false);
                                        }}
                                        className="w-full px-4 py-2 text-left hover:bg-gray-100 flex items-center gap-2 text-red-600"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                        Delete Post
                                    </button>
                                )}
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Content */}
            <p className="text-brand-ebony mb-3 whitespace-pre-wrap font-sans">{post.content}</p>

            {/* Image */}
            {post.imageUrl && (
                <img
                    src={post.imageUrl}
                    alt="Post"
                    className="w-full rounded-lg mb-3"
                />
            )}

            {/* Stats */}
            <div className="flex items-center gap-6 text-xs font-bold text-brand-ebony/40 mb-4 pt-3 uppercase tracking-widest">
                <span className="flex items-center gap-1.5 transition-colors hover:text-brand-burgundy/60 cursor-pointer">
                    <Heart className="w-4 h-4" /> {post.likes?.length || 0} Likes
                </span>
                <span className="flex items-center gap-1.5 transition-colors hover:text-brand-burgundy/60 cursor-pointer">
                    <MessageCircle className="w-4 h-4" /> {post.comments?.length || 0} Comments
                </span>
            </div>

            {/* Actions */}
            <div className="flex items-center gap-3 pt-3 border-t border-brand-ebony/10">
                <button
                    onClick={() => onLike(isLiked)}
                    className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl transition ${isLiked
                        ? 'text-brand-burgundy bg-brand-burgundy/10 font-bold'
                        : 'text-brand-ebony/60 hover:bg-brand-burgundy/5 hover:text-brand-burgundy font-semibold text-sm'
                        }`}
                >
                    <Heart className={`w-4 h-4 ${isLiked ? 'fill-current' : ''}`} />
                    <span>{isLiked ? 'Liked' : 'Like'}</span>
                </button>

                <button
                    onClick={onComment}
                    className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-brand-ebony/60 hover:bg-brand-burgundy/5 hover:text-brand-burgundy transition font-semibold text-sm"
                >
                    <MessageCircle className="w-4 h-4" />
                    <span>Comment</span>
                </button>

                <button className="flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-brand-ebony/60 hover:bg-brand-burgundy/5 hover:text-brand-burgundy transition font-semibold text-sm">
                    <Share2 className="w-4 h-4" />
                    <span>Share</span>
                </button>
            </div>
        </div>
    );
};

