import React, { useState, useEffect, useRef } from 'react';
import { City, ICity } from 'country-state-city';
import { Search, MapPin } from 'lucide-react';

interface LocationAutocompleteProps {
    value: string;
    onChange: (location: string) => void;
}

export function LocationAutocomplete({ value, onChange }: LocationAutocompleteProps) {
    const [query, setQuery] = useState(value);
    const [isOpen, setIsOpen] = useState(false);
    const [results, setResults] = useState<ICity[]>([]);
    const [allCities, setAllCities] = useState<ICity[]>([]);
    const wrapperRef = useRef<HTMLDivElement>(null);

    // Initial load of all cities
    useEffect(() => {
        // country-state-city returns ~140,000 cities globally.
        // We fetch them once when the component mounts.
        const loadCities = async () => {
            const cities = City.getAllCities();
            setAllCities(cities);
        };
        loadCities();
    }, []);

    // Filter cities based on query
    useEffect(() => {
        if (!query.trim()) {
            setResults([]);
            return;
        }

        // Only search if the string typed doesn't exactly match the currently selected value.
        // This prevents the dropdown from staying open and searching if the user selects an option.
        if (query !== value) {
            const searchStr = query.toLowerCase();
            const filtered = allCities
                .filter(city => city.name.toLowerCase().startsWith(searchStr))
                .slice(0, 100); // Limit to top 100 to prevent browser freeze when rendering DOM
            setResults(filtered);
            setIsOpen(true);
        } else {
            setIsOpen(false);
        }
    }, [query, allCities, value]);

    // Update internal query if external value changes (e.g. form reset)
    useEffect(() => {
        if (value !== query) {
            setQuery(value);
        }
    }, [value]);

    // Handle clicking outside to close
    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
                setIsOpen(false);
                // If they clicked away without selecting, we can arguably reset to the last selected value
                // or keep their partial typing. We'll keep their typing but close the dropdown.
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, [wrapperRef]);


    const handleSelect = (city: ICity) => {
        // Format: "City, StateCode, CountryCode"
        const locationString = `${city.name}, ${city.stateCode}, ${city.countryCode}`;
        setQuery(locationString);
        onChange(locationString);
        setIsOpen(false);
    };

    return (
        <div ref={wrapperRef} className="relative w-full">
            <div className="relative">
                <input
                    type="text"
                    placeholder="Search cities (e.g., Jamshedpur)..."
                    value={query}
                    onChange={(e) => {
                        setQuery(e.target.value);
                        // If user clears the input, clear the parent state too
                        if (e.target.value === '') {
                            onChange('');
                        }
                    }}
                    onFocus={() => {
                        if (query.trim() && results.length > 0) setIsOpen(true);
                    }}
                    className="w-full pl-10 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent transition text-gray-900 placeholder:text-gray-400"
                    required
                />
                <MapPin className="w-5 h-5 text-gray-400 absolute left-3 top-1/2 -translate-y-1/2" />
            </div>

            {/* Dropdown Menu */}
            {isOpen && results.length > 0 && (
                <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg max-h-60 overflow-y-auto">
                    {results.map((city, index) => (
                        <button
                            key={`${city.name}-${city.stateCode}-${city.countryCode}-${index}`}
                            type="button"
                            onClick={() => handleSelect(city)}
                            className="w-full text-left px-4 py-2 hover:bg-blue-50 focus:bg-blue-50 focus:outline-none transition-colors border-b border-gray-50 last:border-b-0"
                        >
                            <span className="font-medium text-gray-900">{city.name}</span>
                            <span className="text-gray-500 text-sm ml-2">
                                {city.stateCode}, {city.countryCode}
                            </span>
                        </button>
                    ))}
                </div>
            )}

            {isOpen && query.trim() && results.length === 0 && (
                <div className="absolute z-50 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg p-4 text-center text-gray-500 italic">
                    No cities found matching "{query}"
                </div>
            )}
        </div>
    );
}

'use client';

import React, { createContext, useContext, useEffect, useState, ReactNode } from 'react';
import {
    User as FirebaseUser,
    onAuthStateChanged,
    signInWithEmailAndPassword,
    createUserWithEmailAndPassword,
    signOut as firebaseSignOut
} from 'firebase/auth';
import { doc, getDoc, setDoc, onSnapshot } from 'firebase/firestore';
import { auth, db } from '@/lib/firebase';
import { User } from '@/types';

interface AuthContextType {
    user: FirebaseUser | null;
    userData: User | null;
    loading: boolean;
    error: string | null;
    signIn: (email: string, password: string) => Promise<void>;
    signUp: (email: string, password: string, userData: Partial<User>) => Promise<void>;
    signOut: () => Promise<void>;
    clearError: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
};

interface AuthProviderProps {
    children: ReactNode;
}

export const AuthProvider: React.FC<AuthProviderProps> = ({ children }) => {
    const [user, setUser] = useState<FirebaseUser | null>(null);
    const [userData, setUserData] = useState<User | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const unsubscribe = onAuthStateChanged(auth, async (firebaseUser) => {
            if (firebaseUser) {
                setUser(firebaseUser);

                // Listen to user document changes
                const userDocRef = doc(db, 'users', firebaseUser.uid);
                const unsubscribeUser = onSnapshot(
                    userDocRef,
                    (docSnapshot) => {
                        if (docSnapshot.exists()) {
                            setUserData({ uid: firebaseUser.uid, ...docSnapshot.data() } as User);
                            setLoading(false);
                        } else {
                            console.warn('User document does not exist for UID:', firebaseUser.uid);
                            // Do not setUser(null) here, as it might cause a loop
                            // Just set userData to null and let the UI handle the "Incomplete Setup" state
                            setUserData(null);
                            setLoading(false);
                        }
                    },
                    (err) => {
                        console.error('Error fetching user data snapshot:', err);
                        // If we get a permission-denied error, it's likely because the doc hasn't been created yet
                        // or the rules are too strict.
                        if (err.code === 'permission-denied') {
                            console.warn('Permission denied for user doc. This is expected if the doc is being created.');
                            // Don't set error state yet, give it a moment
                        } else {
                            setError('Failed to load user profile');
                        }
                        setLoading(false);
                    }
                );

                return () => unsubscribeUser();
            } else {
                setUser(null);
                setUserData(null);
                setLoading(false);
            }
        });

        return () => unsubscribe();
    }, []);

    const signIn = async (email: string, password: string) => {
        try {
            setError(null);
            await signInWithEmailAndPassword(auth, email, password);
        } catch (err: unknown) {
            console.error('Sign in error details:', {
                error: err,
                code: (err as { code?: string }).code,
                message: (err as { message?: string }).message
            });
            const error = err as { message?: string };
            setError(error.message || 'Failed to sign in');
            throw err;
        }
    };

    const signUp = async (email: string, password: string, userInfo: Partial<User>) => {
        try {
            setError(null);
            const credential = await createUserWithEmailAndPassword(auth, email, password);

            // Create user document in Firestore
            const userDoc: Partial<User> = {
                uid: credential.user.uid,
                email,
                ...userInfo,
                connections: [],
                pendingRequests: [],
                sentRequests: [],
                groups: [],
                isAdmin: false,
            };

            console.log('User created in Auth, creating Firestore document...');
            await setDoc(doc(db, 'users', credential.user.uid), userDoc);
            console.log('Firestore document created successfully');
        } catch (err: unknown) {
            console.error('Sign up error details:', {
                error: err,
                code: (err as { code?: string }).code,
                message: (err as { message?: string }).message
            });

            // Atomicity: If Auth succeeded but Firestore failed, delete the Auth user 
            // so they can retry without "email-already-in-use" errors.
            if (auth.currentUser) {
                try {
                    console.warn('Deleting Auth user due to Firestore failure...');
                    await auth.currentUser.delete();
                    console.log('Auth user deleted successfully');
                } catch (deleteErr) {
                    console.error('Failed to delete Auth user after sync failure:', deleteErr);
                }
            }

            const error = err as { message?: string };
            setError(error.message || 'Failed to sign up');
            throw err;
        }
    };

    const signOut = async () => {
        try {
            await firebaseSignOut(auth);
        } catch (err: unknown) {
            console.error('Sign out error:', err);
            const error = err as { message?: string };
            setError(error.message || 'Failed to sign out');
            throw err;
        }
    };

    const clearError = () => setError(null);

    const value: AuthContextType = {
        user,
        userData,
        loading,
        error,
        signIn,
        signUp,
        signOut,
        clearError,
    };

    return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

import { imgbbApiKey } from './firebase-config';

/**
 * Uploads a file to ImgBB and returns the download URL
 * @param file The file to upload
 * @param _path Ignored for ImgBB, kept for interface compatibility
 * @returns The download URL of the uploaded file
 */
export const uploadMedia = async (file: File, _path?: string): Promise<string | null> => {
    if (!file) return null;

    if (!imgbbApiKey || (imgbbApiKey as string) === "YOUR_IMGBB_API_KEY") {
        throw new Error("ImgBB API key is not configured.");
    }

    const formData = new FormData();
    formData.append('image', file);

    try {
        const response = await fetch(`https://api.imgbb.com/1/upload?key=${imgbbApiKey}`, {
            method: 'POST',
            body: formData,
        });

        const result = await response.json();

        if (result.success) {
            return result.data.url;
        } else {
            throw new Error(result.error?.message || 'Image upload failed.');
        }
    } catch (error) {
        console.error("ImgBB Upload Error:", error);
        throw error;
    }
};
